solution_code:
#include <iostream>
#include <string>

template <typename T>
struct Labeled
{
    std::string label;
    T value;
};

template <typename T>
Labeled(const char*, T) -> Labeled<T>;

int main()
{
    std::string label1;
    int intVal{};
    std::string label2;
    double dblVal{};

    std::cin >> label1 >> intVal >> label2 >> dblVal;

    Labeled item1{ label1, intVal };
    Labeled item2{ label2, dblVal };

    std::cout << '[' << item1.label << "] " << item1.value << '\n';
    std::cout << '[' << item2.label << "] " << item2.value << '\n';

    return 0;
}
